44‚Üíconst MechanicPanel = ({ user }) => {
45‚Üí  const [calls, setCalls] = useState([]);
46‚Üí  const [filter, setFilter] = useState('ALL');
47‚Üí  const [showCallForm, setShowCallForm] = useState(false);
**48‚Üí  const [callForm, setCallForm] = useState({ machine_id: '', signal_type: 'MECHANIC' });
49‚Üí  const [selectedReasons, setSelectedReasons] = useState([]);
50‚Üí  const [customReason, setCustomReason] = useState('');
51‚Üí  const [showReasons, setShowReasons] = useState(false);
52‚Üí  const [forwardCall, setForwardCall] = useState(null);
53‚Üí  const prevCallsRef = useRef([]);
54‚Üí
55‚Üí  const token = localStorage.getItem('token');
56‚Üí  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
57‚Üí  const API = `http://${window.location.hostname}:8000`;
58‚Üí
59‚Üí  const playAlert = (signalType) => {
60‚Üí    try {
61‚Üí      const ctx = new (window.AudioContext || window.webkitAudioContext)();
62‚Üí      const osc = ctx.createOscillator();
63‚Üí      const gain = ctx.createGain();
64‚Üí      osc.connect(gain);
65‚Üí      gain.connect(ctx.destination);
66‚Üí      gain.gain.value = 0.3;
67‚Üí      if (signalType === 'ELECTRIC') { osc.frequency.value = 660; osc.type = 'sawtooth'; }
68‚Üí      else if (signalType === 'ASNOVA') { osc.frequency.value = 440; osc.type = 'triangle'; }
69‚Üí      else { osc.frequency.value = 520; osc.type = 'sine'; }
70‚Üí      osc.start();
71‚Üí      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
72‚Üí      osc.stop(ctx.currentTime + 1.5);
73‚Üí    } catch (e) {}
74‚Üí  };
75‚Üí
76‚Üí  const fetchCalls = async () => {
77‚Üí    try {
78‚Üí      const res = await fetch(`${API}/mechanic-calls`, { headers });
79‚Üí      if (res.ok) {
80‚Üí        const data = await res.json();
81‚Üí        const newPending = data.filter(c => c.status === 'PENDING');
82‚Üí        const oldPending = prevCallsRef.current.filter(c => c.status === 'PENDING');
83‚Üí        if (newPending.length > oldPending.length) {
84‚Üí          const newCall = newPending.find(nc => !oldPending.some(oc => oc.id === nc.id));
85‚Üí          if (newCall) playAlert(newCall.signal_type || 'MECHANIC');
86‚Üí        }
87‚Üí        prevCallsRef.current = data;
88‚Üí        setCalls(data);
89‚Üí      }
90‚Üí    } catch (e) {}
91‚Üí  };
92‚Üí
93‚Üí  useEffect(() => {
94‚Üí    fetchCalls();
95‚Üí    const i = setInterval(fetchCalls, 3000);
96‚Üí    const h = () => fetchCalls();
97‚Üí    window.addEventListener('app-refresh', h);
98‚Üí    return () => { clearInterval(i); window.removeEventListener('app-refresh', h); };
99‚Üí  }, []);
100‚Üí
101‚Üí  const updateStatus = async (id, status) => {
102‚Üí    try {
103‚Üí      await fetch(`${API}/mechanic-calls/${id}`, {
104‚Üí        method: 'PUT', headers, body: JSON.stringify({ status })
105‚Üí      });
106‚Üí      fetchCalls();
107‚Üí      emitRefresh();
108‚Üí    } catch (e) {}
109‚Üí  };
110‚Üí
111‚Üí  const handleForward = async (callId, newSignalType) => {
112‚Üí    try {
113‚Üí      await fetch(`${API}/mechanic-calls/${callId}`, {
114‚Üí        method: 'PUT', headers, body: JSON.stringify({ status: 'PENDING', signal_type: newSignalType })
115‚Üí      });
116‚Üí      setForwardCall(null);
117‚Üí      fetchCalls();
118‚Üí      emitRefresh();
119‚Üí    } catch (e) {}
120‚Üí  };
121‚Üí
122‚Üí  const handleCreateCall = async () => {
123‚Üí    if (!callForm.machine_id) return;
124‚Üí    let reason = selectedReasons.filter(r => r !== 'Boshqa').join(', ');
125‚Üí    if (customReason) reason += (reason ? ', ' : '') + customReason;
126‚Üí    if (!reason) return;
127‚Üí    try {
128‚Üí      const res = await fetch(`${API}/mechanic-calls`, {
129‚Üí        method: 'POST', headers, body: JSON.stringify({ ...callForm, reason })
130‚Üí      });
131‚Üí      if (res.ok) {
**132‚Üí        setCallForm({ machine_id: '', signal_type: 'MECHANIC' });
133‚Üí        setSelectedReasons([]);
134‚Üí        setCustomReason('');
135‚Üí        setShowReasons(false);
136‚Üí        setShowCallForm(false);
137‚Üí        fetchCalls();
138‚Üí        emitRefresh();
139‚Üí      }
140‚Üí    } catch (e) {}
141‚Üí  };
142‚Üí
143‚Üí  const toggleReason = (reason) => {
144‚Üí    if (reason === 'Boshqa') {
145‚Üí      setSelectedReasons(prev => prev.includes('Boshqa') ? [] : ['Boshqa']);
146‚Üí      setCustomReason('');
147‚Üí    } else {
148‚Üí      setSelectedReasons(prev =>
149‚Üí        prev.includes(reason) ? prev.filter(r => r !== reason) : [...prev.filter(r => r !== 'Boshqa'), reason]
150‚Üí      );
151‚Üí    }
152‚Üí  };
153‚Üí
154‚Üí  const handleSignalChange = (type) => {
**155‚Üí    setCallForm({ ...callForm, signal_type: type });
156‚Üí    setSelectedReasons([]);
157‚Üí    setCustomReason('');
158‚Üí    setShowReasons(true);
159‚Üí  };
160‚Üí
161‚Üí  const hasOther = selectedReasons.includes('Boshqa');
162‚Üí  const currentReasons = REASONS[callForm.signal_type] || REASONS.MECHANIC;
163‚Üí  const currentDirections = DIRECTIONS[callForm.signal_type] || DIRECTIONS.MECHANIC;
164‚Üí
165‚Üí  const statusColors = {
166‚Üí    PENDING: { bg: 'rgba(251,191,36,0.15)', color: '#fbbf24', icon: <Clock size={14} /> },
167‚Üí    IN_PROGRESS: { bg: 'rgba(59,130,246,0.15)', color: '#3b82f6', icon: <Wrench size={14} /> },
168‚Üí    RESOLVED: { bg: 'rgba(34,197,94,0.15)', color: '#22c55e', icon: <CheckCircle size={14} /> },
169‚Üí  };
170‚Üí
171‚Üí  const filtered = filter === 'ALL' ? calls : calls.filter(c => c.status === filter);
172‚Üí  const pendingCount = calls.filter(c => c.status === 'PENDING').length;
173‚Üí  const allMachineIds = Array.from({ length: 68 }, (_, i) => `S${i + 1}`);
174‚Üí
175‚Üí  const canForward = (call) => {
176‚Üí    if (call.status !== 'IN_PROGRESS') return false;
177‚Üí    return ['MECHANIC', 'ELECTRIC', 'ASNOVA', 'ADMIN', 'MASTER', 'NAZORATCHI', 'UZLAVYAZ'].includes(user.role);
178‚Üí  };
179‚Üí
180‚Üí  const forwardTargets = (call) => {
181‚Üí    const targets = [];
182‚Üí    if (call.signal_type === 'MECHANIC') {
183‚Üí      targets.push({ value: 'ELECTRIC', label: 'Elektrikga', icon: '‚ö°' });
184‚Üí      targets.push({ value: 'ASNOVA', label: 'Uzlavyazga', icon: 'üßµ' });
185‚Üí    } else if (call.signal_type === 'ELECTRIC') {
186‚Üí      targets.push({ value: 'MECHANIC', label: 'Mexanikka', icon: 'üîß' });
187‚Üí      targets.push({ value: 'ASNOVA', label: 'Uzlavyazga', icon: 'üßµ' });
188‚Üí    } else if (call.signal_type === 'ASNOVA') {
189‚Üí      targets.push({ value: 'MECHANIC', label: 'Mexanikka', icon: 'üîß' });
190‚Üí      targets.push({ value: 'ELECTRIC', label: 'Elektrikga', icon: '‚ö°' });
191‚Üí    }
192‚Üí    return targets;
193‚Üí  };
194‚Üí
195‚Üí  const getDirectionLabel = (dir) => {
196‚Üí    const allDirs = [...DIRECTIONS.MECHANIC, ...DIRECTIONS.ASNOVA];
197‚Üí    const found = allDirs.find(d => d.value === dir);
198‚Üí    return found ? found.label : dir;
199‚Üí  };
200‚Üí
201‚Üí  return (
202‚Üí    <div style={{ padding: '1.5rem' }}>
203‚Üí      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '8px' }}>
204‚Üí        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '10px' }}>
205‚Üí          <Wrench size={24} />
206‚Üí          Chaqiruvlar
207‚Üí          {pendingCount > 0 && (
208‚Üí            <span style={{
209‚Üí              background: '#ef4444', color: 'white', borderRadius: '50%',
